#!/usr/bin/env python3
"""HARD query set — the unsaturated instrument.

WHY THIS EXISTS. The base 36-query set (`eval_queryset.py`) measured fleet HEADROOM at
+0.028 and could not settle the verdict, because **31 of its 36 queries have the best
candidate already pinned at the grader's maximum**. Where the top candidate scores 1.0,
headroom is 0 BY CONSTRUCTION — the grader cannot go higher, so no disagreement can
show even if it exists. The whole +0.028 was earned on 5 queries. You cannot diagnose a
fleet with an instrument stuck at its ceiling.

So this set has ONE job: **make the best candidate lose points.** Not "make the models
disagree" — that would be rigging the experiment. Just remove the ceiling and see what
is underneath.

HOW THE CEILING IS REMOVED. The grader scores 0-5 on "correct AND COMPLETE" against the
reference. The base set's references are single-point facts ($0.05; 3 minutes;
`list(dict.fromkeys(xs))`) — a model that gets the point gets 5/5, and saturates. Every
reference here instead enumerates **several independently checkable components**: a
mechanism, a precise value, a fix, a named edge case, a common wrong answer to reject.
Partial credit becomes the norm rather than the exception, so the grader has resolution
in the range where these models actually live.

Difficulty comes from the PROBLEM, not from a stingy rubric. Each query is drawn from
the specialist's genuine domain and has an unambiguous correct answer; the reference
only states faithfully what a complete answer must contain.

PRE-REGISTERED — DO NOT TUNE AGAINST OBSERVED CANDIDATES.
These 30 queries were written and frozen BEFORE any candidate response was generated.
That matters: if you edit them after seeing which model wins what, you are selecting for
disagreement and MANUFACTURING the headroom this instrument exists to measure — and the
resulting number means nothing. If a query turns out to be broken (ambiguous, or the
reference is simply wrong), DELETE it and say so in the report. Never re-word one to
change who wins.

The honest outcomes are both informative:
  * headroom stays ~0 on hard, unsaturated queries -> the fleet is genuinely REDUNDANT.
    Three models, one opinion. Route or cascade; do not judge.
  * headroom appears -> the base set's ceiling was hiding real disagreement all along,
    and the ensemble+judge question is live again.

Generating candidates for these REQUIRES A GPU BOOT (the specialists are self-hosted):
    CONCLAVE_QUERYSET=hard CONCLAVE_GW=<ts-ip>:4000 python3 orchestrator/candidate_cache.py
Then, offline:
    CONCLAVE_QUERYSET=hard python3 orchestrator/divergence.py

10 per category (n=30), balanced, same three categories as the base set.
"""
from __future__ import annotations

HARD_QUERY_SET: list[dict] = [
    # ================= coder: Qwen2.5-Coder-14B expected strongest =================
    # Each asks for mechanism + fix + a distinction, not a one-liner. A model that
    # produces the right incantation but cannot say WHY loses points, as it should.
    {"id": "hardcoder-closure-late-binding", "category": "coder",
     "prompt": "`fs = [lambda: i for i in range(3)]` then `[f() for f in fs]` gives [2, 2, 2] instead of [0, 1, 2]. Explain precisely why, give two different correct fixes, and say what each fix actually changes.",
     "reference": "Python closures capture the VARIABLE, not its value (late binding). All three lambdas share the same cell for `i`; the comprehension finishes with i == 2, and only then are the lambdas called, so each returns 2. Fix 1: bind per-iteration with a default argument, `[lambda i=i: i for i in range(3)]` — default arguments are evaluated at DEFINITION time, snapshotting the current value into the function object. Fix 2: `functools.partial`, `[partial(lambda i: i, i) for i in range(3)]` — partial also binds the value eagerly at definition. (A third: a factory function returning the lambda, giving each a fresh enclosing scope.) What both fixes change is WHEN `i` is evaluated: at definition rather than at call."},
    {"id": "hardcoder-eq-without-hash", "category": "coder",
     "prompt": "I added `__eq__` to a class and now its instances can't be used as dict keys or put in a set. Why, and what are my options?",
     "reference": "Defining `__eq__` sets `__hash__` to None in Python 3, making instances unhashable. That is deliberate: the contract requires a == b to imply hash(a) == hash(b), and the inherited identity-based hash would violate it for objects that are equal but not identical. Options: (1) define `__hash__` consistently with `__eq__`, over the SAME fields — `def __hash__(self): return hash((self.x, self.y))` — valid only if those fields are effectively immutable; (2) `__hash__ = object.__hash__` to keep identity semantics, correct only if equality is identity-compatible (usually it isn't); (3) use `@dataclass(frozen=True)`, which generates a consistent `__eq__` and `__hash__` together. Regardless: mutating an object after using it as a key corrupts the dict, because its hash bucket no longer matches — hash keys must be immutable."},
    {"id": "hardcoder-blocking-in-async", "category": "coder",
     "prompt": "My asyncio server hangs under load. Inside an `async def` handler I call `requests.get(url)` and `time.sleep(1)`. Wrapping the handlers in `asyncio.gather` didn't help. Explain what is actually happening and how to fix it properly.",
     "reference": "Both calls are synchronous and BLOCKING, so they block the single event-loop thread. While one handler sits in `requests.get` or `time.sleep`, the loop cannot run any other coroutine — so the handlers execute one after another and `gather` buys nothing. `async def` does not make code asynchronous; only awaiting a non-blocking primitive yields control back to the loop. Fix: replace blocking calls with async equivalents — `await asyncio.sleep(1)` instead of `time.sleep(1)`, and an async HTTP client (`aiohttp` or `httpx.AsyncClient`) instead of `requests`. If you must call blocking or CPU-bound code you cannot replace, offload it off the loop thread: `await asyncio.to_thread(fn, ...)` (or `loop.run_in_executor(...)`, with a ProcessPoolExecutor for CPU-bound work)."},
    {"id": "hardcoder-generator-exhaustion", "category": "coder",
     "prompt": "`g = (x*x for x in range(5))` — then `sum(g)` prints 30 and a second `sum(g)` prints 0. Why? When is a list the right choice instead, and when is it not?",
     "reference": "A generator is a ONE-SHOT iterator: the first sum() consumes it to exhaustion, so the second sum() iterates zero items and returns 0 (an exhausted generator raises StopIteration immediately — it does not restart). This is by design, not a bug. Use a list/tuple when you need to iterate more than once, index into it, or take len(). Keep the generator when the sequence is large or infinite, or you only pass over it once, because it is lazy and O(1) in memory rather than materializing every element. If you need BOTH re-iterability and laziness, return a fresh generator each time — make it an iterable rather than an iterator, e.g. `def squares(): return (x*x for x in range(5))`, calling `squares()` per pass (or write a class with `__iter__`)."},
    {"id": "hardcoder-money-float-decimal", "category": "coder",
     "prompt": "Why shouldn't I use `float` for currency, and what exactly should I use in Python instead? Also: what does `round(2.675, 2)` return, and why? And separately, what does Python's `round()` do on an exact half, like `round(0.5)` and `round(2.5)`?",
     "reference": "Binary floating point cannot represent most decimal fractions (0.1, 0.01, 2.675) exactly, so arithmetic accumulates representation error and totals drift by cents — unacceptable for money. Use `decimal.Decimal`, constructed from STRINGS (`Decimal('0.10')`, never `Decimal(0.10)`, which just inherits the float's error), with explicit `quantize()`/context for rounding; or store integer minor units (cents) as int and divide only for display. `round(2.675, 2)` returns 2.67, NOT 2.68 — because 2.675 is not stored as 2.675 but as slightly less (2.67499999999999982...), so the nearest 2-decimal value really is 2.67. Separately, Python's round() uses banker's rounding (round-half-to-even) on exact ties, so round(0.5) == 0 and round(2.5) == 2 — a second surprise that is NOT the cause of this one."},
    {"id": "hardcoder-threading-race-gil", "category": "coder",
     "prompt": "Two threads each run `counter += 1` a million times, and the final value is less than two million — even though Python has a GIL. Explain why the GIL doesn't prevent this, and fix it.",
     "reference": "`counter += 1` is NOT atomic. It compiles to several bytecodes — load the value, add one, store it back — and the interpreter can release the GIL BETWEEN bytecodes (at a switch interval). So two threads can both load the same value, both add one, and both store the same result: one increment is lost. The GIL serializes the EXECUTION of bytecode; it does not make a compound read-modify-write operation atomic. Fix: make the update mutually exclusive — `with lock: counter += 1` using a `threading.Lock` — or have each thread accumulate a private local count and combine the totals at the end (far less lock contention), or use a queue. Note that for CPU-bound work threads give no parallelism at all under the GIL; that is a separate reason to use processes."},
    {"id": "hardcoder-mutable-class-attr", "category": "coder",
     "prompt": "In `class Dog: tricks = []`, adding a trick to one dog adds it to every dog. Explain the mechanism precisely, and give the fix.",
     "reference": "`tricks = []` is a CLASS attribute: one list object, created once when the class body executes, shared by every instance. `self.tricks.append(x)` MUTATES that shared object — attribute lookup finds no instance attribute, falls back to the class attribute, and appends to it. The crucial distinction: mutation via `self.tricks.append(...)` never creates an instance attribute, whereas ASSIGNMENT (`self.tricks = [...]`) would shadow the class attribute with a new per-instance one. Fix: create the list per instance in `__init__` — `def __init__(self): self.tricks = []`. With dataclasses, use `field(default_factory=list)`; a bare `tricks: list = []` raises ValueError precisely to stop this bug."},
    {"id": "hardcoder-is-vs-eq-interning", "category": "coder",
     "prompt": "Typed at the REPL, `a = 256; b = 256; a is b` gives True, but `a = 257; b = 257; a is b` gives False. And two identical strings are sometimes `is`-identical and sometimes not. Explain what is going on, and state the rule for when to use `is`.",
     "reference": "CPython pre-allocates and caches the small integers -5..256, so every 256 is literally the same object and `is` is True. 257 is outside that cache and each occurrence may build a fresh object, so identity differs. Strings behave similarly: literals that look like identifiers are INTERNED at compile time (so `is` happens to work), while strings built at runtime generally are not. All of this is a CPython IMPLEMENTATION DETAIL — not a language guarantee — and may differ by version, by interpreter, or even between the REPL and a compiled module. The rule: use `is` ONLY for identity against singletons — `is None`, `is True`/`is False`, module-level sentinel objects — and use `==` for value equality, always. `is` returning True for equal values is a coincidence of interning, never something to rely on."},
    {"id": "hardcoder-lru-design", "category": "coder",
     "prompt": "Design a cache with O(1) get and O(1) put that evicts the least-recently-used key when it is full. Name the data structures, justify why each operation is O(1), and state precisely what breaks if you try to do it with a plain dict alone.",
     "reference": "A hash map plus a DOUBLY-linked list. The dict maps key -> node; the linked list holds the nodes in recency order (most-recently-used at the head, least-recently-used at the tail). get: dict lookup is O(1) to find the node, then unlink it and splice it to the head — O(1) because the node carries prev/next pointers, so no scan is needed to find its neighbours (this is exactly why the list must be doubly linked; a singly linked list cannot unlink in O(1)). put: create a node at the head and insert into the dict, both O(1); if over capacity, evict the TAIL node — O(1) because the LRU element is directly reachable — and delete its key from the dict (which is why the node must also store its key). A plain dict alone cannot do it: nothing records ACCESS ORDER, so finding the least-recently-used key means either scanning all entries (O(n)) or storing timestamps and scanning for the minimum (still O(n)). In Python, `collections.OrderedDict` (move_to_end / popitem(last=False)) gives you exactly this behaviour; `functools.lru_cache` uses the same underlying structure internally — a plain dict plus a circular doubly-linked list — rather than being built on OrderedDict itself."},
    {"id": "hardcoder-sort-stability-multikey", "category": "coder",
     "prompt": "Sort records by department ASCENDING, then by salary DESCENDING within each department. Give the correct single-pass solution, and explain how you would do it if the secondary key could not be negated (say it is a string).",
     "reference": "Single pass: `sorted(rs, key=lambda r: (r.dept, -r.salary))`. Tuple keys compare left to right, and negating just the numeric field flips the direction of that field only. Note `reverse=True` cannot help here: it reverses the WHOLE key, so one call cannot mix directions. If the secondary key cannot be negated (a string), exploit STABILITY and sort twice, secondary key FIRST, then primary: `rs.sort(key=lambda r: r.name, reverse=True)` then `rs.sort(key=lambda r: r.dept)`. Python's sort is stable (Timsort), so the second sort preserves the relative order the first established within each department. The order matters — sorting primary-then-secondary would destroy the secondary ordering. (`functools.cmp_to_key` with a custom comparator is the last resort, and slower.)"},

    # ============== reasoning: DeepSeek-R1-distill-7B expected strongest ==============
    # Multi-step, with a precise checkable answer AND a required derivation. Several have
    # a strong intuitive wrong answer, so a model that pattern-matches instead of
    # computing lands on a confident, fluent, wrong number.
    {"id": "hardreason-bayes-disease", "category": "reasoning",
     "prompt": "A disease affects 1 in 1000 people. A test is 99% sensitive (it is positive 99% of the time when you have the disease) and has a 5% false-positive rate. You test positive. What is the probability you actually have the disease? Show the calculation.",
     "reference": "About 1.9% (roughly 1 in 51). By Bayes: P(D) = 0.001, so P(+ and D) = 0.001 x 0.99 = 0.00099. P(not D) = 0.999, so P(+ and not D) = 0.999 x 0.05 = 0.04995. P(D | +) = 0.00099 / (0.00099 + 0.04995) = 0.00099 / 0.05094 = 0.0194, i.e. ~1.9%. The base rate dominates: because the healthy population is ~1000x larger, its 5% false positives (about 50 per 1000 people) vastly outnumber the ~1 true positive. The answer is NOT 99% — believing so is the base-rate fallacy, which confuses P(+ | D) with P(D | +)."},
    {"id": "hardreason-birthday", "category": "reasoning",
     "prompt": "In a room of 23 people, what is the probability that at least two share a birthday? Give the reasoning and explain why the answer surprises people.",
     "reference": "About 50.7% — just over half. Compute the COMPLEMENT: P(all 23 distinct) = (365/365) x (364/365) x (363/365) x ... x (343/365), which is about 0.4927; so P(at least one shared) = 1 - 0.4927 = 0.5073. It surprises people because they unconsciously answer a different question — 'does someone share MY birthday?', which needs about 253 people to reach 50%. The actual question is about ANY pair, and 23 people form C(23,2) = 253 pairs, each an opportunity to collide. The number of pairs grows QUADRATICALLY in the number of people, not linearly, which is why so few people suffice."},
    {"id": "hardreason-expected-rolls", "category": "reasoning",
     "prompt": "For a fair six-sided die: what is the expected number of rolls to get your first 6? And what is the expected number of rolls to see all six faces at least once? Show the reasoning for both.",
     "reference": "First 6: 6 rolls. The number of rolls is geometric with success probability p = 1/6, and a geometric distribution has expectation 1/p = 6. All six faces (the coupon-collector problem): about 14.7 rolls. Reasoning: once you already hold k distinct faces, the chance that the next roll shows a NEW face is (6-k)/6, so the expected wait for that new face is 6/(6-k) rolls. Summing over k = 0,1,2,3,4,5 gives 6/6 + 6/5 + 6/4 + 6/3 + 6/2 + 6/1 = 6 x (1 + 1/2 + 1/3 + 1/4 + 1/5 + 1/6) = 6 x H_6 = 6 x 2.45 = 14.7 rolls."},
    {"id": "hardreason-two-coins", "category": "reasoning",
     "prompt": "Two fair coins are flipped and hidden from you. Case 1: you are told 'at least one is heads.' What is the probability both are heads? Case 2: instead you are told 'the first coin is heads.' What is the probability both are heads? Explain why the two answers differ.",
     "reference": "Case 1: 1/3. Case 2: 1/2. The equally likely outcomes are HH, HT, TH, TT. 'At least one is heads' rules out only TT, leaving three equally likely outcomes — HH, HT, TH — of which exactly one is HH, so 1/3. Naming a SPECIFIC coin ('the first is heads') rules out TT and TH, leaving HH and HT, so 1/2. They differ because the two statements condition on different events: 'at least one' is a claim about the PAIR and does not say WHICH coin is heads, so it keeps both HT and TH alive; identifying a particular coin eliminates TH as well. The information content of the condition is what matters, not merely the fact that a head exists. (This is the boy-or-girl paradox.)"},
    {"id": "hardreason-pipes-drain", "category": "reasoning",
     "prompt": "Pipe A fills a tank in 4 hours. Pipe B fills the same tank in 6 hours. Drain C empties a full tank in 3 hours. All three are opened on an empty tank. Does the tank ever fill? If so, when?",
     "reference": "Yes — it fills in 12 hours. Work in rates of tank per hour: A = +1/4, B = +1/6, C = -1/3. Net rate = 1/4 + 1/6 - 1/3 = 3/12 + 2/12 - 4/12 = +1/12 tank per hour. Since the net rate is POSITIVE the tank does fill, and the time is 1 / (1/12) = 12 hours. The trap is to assume the drain wins because it is the fastest single pipe (3 hours beats 4 and 6); it does not, because the two inlets act TOGETHER — combined they add 5/12 per hour against the drain's 4/12."},
    {"id": "hardreason-last-digit", "category": "reasoning",
     "prompt": "What is the last digit of 7 raised to the power 222? Show the reasoning.",
     "reference": "9. Work modulo 10. Powers of 7 cycle with period 4: 7^1 = 7, 7^2 = 49 -> 9, 7^3 = 343 -> 3, 7^4 = 2401 -> 1, and then the cycle 7, 9, 3, 1 repeats. So the last digit depends only on the exponent modulo 4. 222 = 4 x 55 + 2, so 222 is congruent to 2 mod 4, and 7^222 is congruent to 7^2 = 49, which is 9 mod 10. The last digit is 9."},
    {"id": "hardreason-seating-constraint", "category": "reasoning",
     "prompt": "In how many ways can 5 people be seated in a row if two specific people, Alice and Bob, must NOT sit next to each other? Show the reasoning.",
     "reference": "72. Count the complement. Total arrangements of 5 people in a row: 5! = 120. Now count the arrangements where Alice and Bob ARE adjacent: glue them into a single block, giving 4 objects (the block plus the other 3 people) to arrange in 4! = 24 ways, and multiply by 2 for the two internal orders of the block (Alice-Bob and Bob-Alice): 24 x 2 = 48. So the not-adjacent count is 120 - 48 = 72. Complement counting is the clean route here; counting the non-adjacent seatings directly is far more error-prone."},
    {"id": "hardreason-three-boxes", "category": "reasoning",
     "prompt": "Three boxes are labeled 'Apples', 'Oranges', and 'Apples & Oranges'. Every single label is wrong. You may draw ONE fruit from ONE box, without looking inside. Which box do you draw from, and how do you then deduce the contents of all three?",
     "reference": "Draw from the box labeled 'Apples & Oranges'. Because every label is wrong, that box cannot actually be the mixed one — so it is PURE, all apples or all oranges, and the single fruit you draw identifies it with certainty. Suppose you draw an apple: that box is Apples. The two remaining contents are Oranges and Mixed. The box labeled 'Oranges' cannot contain oranges (its label is wrong), so it must be the Mixed box; therefore the box labeled 'Apples' is the Oranges box. (Symmetric if you draw an orange.) Drawing from either of the other two boxes does NOT work: e.g. drawing an apple from the box labeled 'Apples' only tells you it is Apples-or-Mixed, and the remaining assignment is not forced — one draw leaves the puzzle unresolved. The all-labels-wrong condition is what makes the mixed-labeled box the uniquely informative choice."},
    {"id": "hardreason-st-petersburg", "category": "reasoning",
     "prompt": "A game: a fair coin is flipped repeatedly until it lands tails. You win 2^n dollars, where n is the number of heads before that first tail. What is the expected payout, and what should you actually be willing to pay to play? Explain the tension.",
     "reference": "The expected payout is INFINITE. The probability of exactly n heads followed by a tail is (1/2)^(n+1), and the payout is 2^n, so each n contributes 2^n x (1/2)^(n+1) = 1/2 to the expectation. Summing over all n >= 0 gives 1/2 + 1/2 + 1/2 + ... which DIVERGES: E = infinity. Yet almost nobody would pay even a moderately large finite sum to play — this is the St. Petersburg paradox. The tension resolves on several grounds: the enormous payouts carry vanishing probability, so you need astronomically many plays to realize them; any real house has a FINITE bankroll, which truncates the sum to a modest finite value; and the utility of money is concave (diminishing marginal utility), so expected UTILITY is finite even when expected dollars is not. The lesson: maximizing raw expected value is the wrong decision rule when the distribution has an unbounded tail."},
    {"id": "hardreason-clock-overlaps", "category": "reasoning",
     "prompt": "How many times do the hour and minute hands of a 12-hour analog clock overlap in 24 hours, and at what interval? Explain why the count is not simply once per hour. Give the exact time of the first overlap after 12:00.",
     "reference": "22 times in 24 hours — that is 11 times per 12-hour cycle, NOT 12. The minute hand travels 360 degrees per hour and the hour hand 30, so the minute hand gains 330 degrees per hour on it; it therefore laps the hour hand once every 360/330 = 12/11 hours, which is about 65 minutes 27.3 seconds (not 65 minutes, and not once per hour). In 12 hours it laps 12 / (12/11) = 11 times, hence 22 in 24 hours. The count is 11 rather than 12 because the overlap that would fall near 11:00 is exactly the 12:00 one — the hands meet at 12:00 and only meet 10 more times before returning there. The first overlap after 12:00 is at 12/11 hours = 1 hour 5 minutes 27 3/11 seconds, i.e. approximately 1:05:27."},

    # ================ general: Gemma-2-9B expected strongest ================
    # Explanation under a completeness bar: each demands a mechanism, a named
    # misconception, and a limit. Fluent-but-shallow answers score mid, not max.
    {"id": "hardgen-cap-theorem", "category": "general",
     "prompt": "Explain the CAP theorem, the single most common misconception about it, and what it actually forces you to choose between in practice. Also: what does CAP say about the case where there is NO partition, and what does PACELC add?",
     "reference": "CAP: in a distributed data store, when a network PARTITION occurs you cannot simultaneously have Consistency (every read sees the latest write) and Availability (every request receives a non-error response) — you must give one up. The most common misconception is that you 'pick 2 of the 3' as a standing design property, and that a 'CA system' is a real option. It is not: partitions are a FACT of networks, not a design choice you can decline. P is forced on you. So the real choice is only what the system does DURING a partition: CP (refuse requests / return errors rather than serve possibly-stale data) or AP (keep serving, accept staleness, reconcile afterwards). A second point often missed: CAP says NOTHING about the normal, non-partitioned case — and that is where systems actually spend their time. There the trade is latency against consistency, which is what PACELC adds (Else: Latency vs Consistency)."},
    {"id": "hardgen-idempotency", "category": "general",
     "prompt": "What does 'idempotent' mean for an API, why does it matter, and which HTTP methods are idempotent? Include the subtlety people usually get wrong.",
     "reference": "Idempotent means that making the same request many times has the same effect on SERVER STATE as making it once. The subtlety people get wrong: idempotency is about state, NOT about the response — the responses may legitimately differ (a first DELETE returns 204, a repeat returns 404), and that does not make DELETE non-idempotent. It matters because networks fail: when a client times out it cannot know whether the request actually landed, and it can only safely RETRY if the operation is idempotent — otherwise the retry double-charges the customer. Idempotent methods: GET, HEAD, PUT, DELETE, OPTIONS, TRACE. NOT idempotent: POST. PATCH is not guaranteed idempotent (it depends on the patch body). A stronger property is SAFE — no state change at all: GET, HEAD, OPTIONS, TRACE (RFC 9110 defines exactly these four; every safe method is necessarily idempotent, but not conversely — PUT and DELETE are idempotent and NOT safe). For inherently non-idempotent operations (creating a payment), the standard remedy is an idempotency KEY supplied by the client, which the server records so it can recognize and dedupe a retry."},
    {"id": "hardgen-eventual-consistency", "category": "general",
     "prompt": "Explain eventual consistency to a senior engineer who only knows ACID databases: what guarantee do you actually get, what breaks, and what does 'read your own writes' mean?",
     "reference": "The guarantee is weak and purely asymptotic: IF writes stop, all replicas will eventually CONVERGE to the same value. There is no bound on when, and no promise whatsoever about what any individual read returns in the meantime. What breaks: a read issued immediately after your own write can return STALE data if it lands on a lagging replica; two concurrent writes to the same key can conflict and need a resolution rule — last-write-wins is simple and SILENTLY DISCARDS data, while CRDTs or vector clocks preserve more at the cost of complexity; and cross-record invariants ('balance never goes negative') cannot be enforced globally, because no replica sees all the writes in time. 'Read your own writes' is a SESSION guarantee that sits between the two extremes: a given client is guaranteed to observe its OWN prior writes — usually implemented by pinning that client to one replica, or by having it carry a version token the read must satisfy — even though it may still not see other clients' recent writes. It is one of a family of session guarantees, alongside monotonic reads (never go backwards in time) and monotonic writes."},
    {"id": "hardgen-oauth-vs-authn", "category": "general",
     "prompt": "Explain the difference between authentication and authorization, and why OAuth 2.0 is not an authentication protocol despite everyone using it to log in.",
     "reference": "Authentication establishes WHO you are (identity); authorization establishes WHAT you are permitted to do (access). OAuth 2.0 is a DELEGATED AUTHORIZATION framework: it lets a user grant a third-party application limited access to their resources on another service, and what it issues is an access token meaning roughly 'the bearer of this may do X'. That token says nothing reliable about identity — it is a bearer credential, so possession is the only claim it makes, and the receiving app cannot verify from it WHO the token was issued for, or even that it was issued for that app at all (the confused-deputy problem). Using a raw OAuth access token as proof of login is therefore the classic mistake. OpenID Connect (OIDC) is the identity layer built ON TOP of OAuth 2.0 that does authentication properly: it adds an ID token — a signed JWT with verifiable issuer, audience and subject claims — which the app validates. So the rule is: OAuth 2.0 for access, OIDC for identity."},
    {"id": "hardgen-index-tradeoff", "category": "general",
     "prompt": "When does adding a database index make things WORSE? Give the mechanisms, not just 'writes get slower'.",
     "reference": "(1) Write amplification: every INSERT, UPDATE or DELETE touching an indexed column must also update each such index — so one row write becomes several page writes, plus B-tree page splits and rebalancing as the index grows. More indexes multiply this. (2) Memory/cache pressure: indexes take real space, sometimes rivalling the table, and they compete for the buffer pool — a large index that no query uses still evicts hot data pages from RAM, hurting reads it never serves. (3) Low selectivity: an index on a column with few distinct values (a boolean, a 3-value status) rarely pays, because matching rows are scattered and fetching them through the index means RANDOM I/O plus a heap lookup per row; a sequential scan of the table can be strictly faster, and a good planner will ignore your index. (4) Planner regressions: statistics can go stale or mislead, and the optimizer may then choose the new index for a query that was previously fine, making it slower. The discipline: index for the queries you actually run, verify with EXPLAIN/EXPLAIN ANALYZE that it is chosen and helps, and drop indexes nothing uses."},
    {"id": "hardgen-p-value", "category": "general",
     "prompt": "Explain what a p-value actually is, and give the two most common misinterpretations of it.",
     "reference": "A p-value is the probability of observing data AT LEAST AS EXTREME as what you actually observed, ASSUMING the null hypothesis is true — that is, P(data this extreme | H0). It is a statement about the data under an assumed hypothesis, not about the hypothesis. Misinterpretation 1: reading it as the probability that the null hypothesis is TRUE given the data, P(H0 | data). That is the inverted conditional; getting it would require a prior and Bayes' theorem, and a small p-value simply does not deliver it. Misinterpretation 2: reading a small p as meaning the effect is LARGE or important. The p-value speaks only to compatibility with H0, not to effect SIZE — with a large enough sample, a trivially small and practically meaningless effect produces an arbitrarily tiny p. (A third, nearly as common: treating p >= 0.05 as evidence that there is NO effect — absence of evidence is not evidence of absence, especially in an underpowered study.) The remedy is to report effect sizes and confidence intervals alongside, not p alone."},
    {"id": "hardgen-unicode-utf8", "category": "general",
     "prompt": "What is the difference between Unicode, UTF-8, and an error like `UnicodeDecodeError`? And explain why `len()` of a string can surprise you.",
     "reference": "Unicode is a CHARACTER SET / standard: it assigns every character an abstract number called a code point (U+0041 is 'A'). UTF-8 is an ENCODING: a concrete rule for turning code points into BYTES — variable width, 1 to 4 bytes per code point, and backward-compatible with ASCII. The relationship: text in memory is code points; text on disk or on the wire is bytes; you ENCODE on the way out and DECODE on the way in. A UnicodeDecodeError means you decoded bytes with the WRONG encoding — the byte sequence is not valid under the rule you applied (e.g. reading a UTF-8 file as ASCII, or as latin-1 where it silently produces mojibake instead). len() surprises because in Python 3 len(str) counts CODE POINTS — not bytes, and not what a human would call a character. So 'é' may be length 1 (precomposed, U+00E9) or length 2 (an 'e' plus a combining accent) for identical-looking text; and an emoji with a skin-tone modifier, or a ZWJ family emoji, is several code points despite rendering as ONE grapheme cluster. The byte length is different again: len(s.encode('utf-8'))."},
    {"id": "hardgen-microservices", "category": "general",
     "prompt": "A team wants to split their monolith into microservices for 'scalability'. Give the strongest case for, the strongest case against, and name the thing that most often goes wrong.",
     "reference": "The strongest case FOR is independent deployability and team autonomy: separate services can be built, released, scaled and owned by separate teams, so a large organization stops serializing every change through one build, test and deploy pipeline; you also get failure and resource isolation, and can scale only the hot component. The strongest case AGAINST is that you replace in-process function calls with the NETWORK: every call can now fail, time out, retry, or arrive twice, and you inherit the full set of distributed-systems problems — partial failure, eventual consistency across service boundaries, distributed tracing, versioned contracts — plus a large operational burden (deployment, service discovery, observability). Crucially, SCALABILITY ALONE RARELY JUSTIFIES IT: a monolith scales horizontally perfectly well behind a load balancer, so throughput is usually the wrong reason; the genuine driver is organizational (team independence at scale). What most often goes wrong is that the split follows the wrong BOUNDARIES — services that share a database, or that must be deployed together in lockstep, produce a 'distributed monolith' that pays every cost of the network and buys none of the autonomy. Boundaries should follow business capabilities / bounded contexts, with each service owning its own data."},
    {"id": "hardgen-cache-invalidation", "category": "general",
     "prompt": "Explain cache invalidation strategies — TTL, write-through, and explicit invalidation — with the failure mode of each. Then explain a cache stampede (thundering herd) and how to prevent it.",
     "reference": "TTL (expire after N seconds): simple, and self-healing because every wrong entry eventually dies; the failure mode is that you knowingly serve STALE data for up to the TTL, and the value is a guess — short TTLs destroy the hit rate, long TTLs prolong staleness. Write-through (write to cache and to the store together): keys written through that path are always fresh; the failure modes are that every write now pays cache latency, and that it does NOT help when another process, service or a batch job writes to the store directly, bypassing the cache (the related write-behind/write-back adds a durability risk — acknowledged writes can be lost before they reach the store). Explicit invalidation (delete or update the key when the underlying data changes): the freshest and most precise; the failure mode is that it is the hardest to get right — you must find EVERY writer and every derived or dependent key, and any path you miss serves stale data FOREVER, because unlike TTL it never self-heals; it is also racy, since a delete can interleave with a concurrent read that then re-populates the cache with the old value. A cache stampede / thundering herd happens when a hot key expires and many concurrent requests all miss at once, and all of them hit the database simultaneously — which can overwhelm it, and the resulting slow recompute keeps the key missing, so the herd grows. Prevent it with: single-flight / a per-key lock so only ONE request recomputes while the rest wait or serve the stale value; serve-stale-while-revalidate (return the old entry and refresh in the background); probabilistic or early recomputation before the TTL expires; and JITTERED TTLs, so keys populated together do not all expire together."},
    {"id": "hardgen-concurrency-vs-parallelism", "category": "general",
     "prompt": "Explain the difference between concurrency and parallelism, why a single-threaded async server can outperform a thread-per-request one, and when it definitively cannot.",
     "reference": "Concurrency is a STRUCTURING property: many tasks are in progress at once and make progress by interleaving — dealing with many things at once. Parallelism is an EXECUTION property: multiple things literally run at the same instant, which requires multiple cores. You can have concurrency on a single core; you cannot have parallelism there. A single-threaded async server outperforms thread-per-request for I/O-BOUND work, for two distinct reasons: (1) most of a request's wall-clock time is spent WAITING on the network, disk or database, and while one request waits the event loop runs another, so one thread can keep thousands of connections in flight; (2) it avoids the per-thread costs — each OS thread needs its own stack (often megabytes), so ten thousand threads is gigabytes of memory plus heavy context-switching and lock contention, whereas ten thousand coroutines are cheap heap objects. This is the classic C10K argument. It definitively CANNOT win for CPU-BOUND work: one thread is one core, so if requests are computing rather than waiting there is nothing to interleave — the loop is already saturated, and worse, any long blocking computation stalls EVERY other request on that loop (head-of-line blocking). For CPU-bound work you need genuine parallelism: multiple processes or threads spread across cores — in practice, one async event loop PER core."},
]


def by_category() -> dict[str, list[dict]]:
    out: dict[str, list[dict]] = {}
    for q in HARD_QUERY_SET:
        out.setdefault(q["category"], []).append(q)
    return out


def demo() -> None:
    """Offline self-check — the hard set is well-formed and distinct from the base set."""
    from eval_queryset import QUERY_SET

    ids = [q["id"] for q in HARD_QUERY_SET]
    assert len(ids) == len(set(ids)), "duplicate query ids"
    cats = {q["category"] for q in HARD_QUERY_SET}
    assert cats == {"coder", "reasoning", "general"}, f"unexpected categories: {cats}"

    # Ids must not collide with the base set: the candidate cache and the grade cache are
    # both keyed by query id, so a collision would silently graft a base candidate onto a
    # hard query (or serve a base grade for a hard answer) and corrupt both runs at once.
    base_ids = {q["id"] for q in QUERY_SET}
    assert not (set(ids) & base_ids), f"id collides with the base set: {set(ids) & base_ids}"

    counts = {c: len(v) for c, v in by_category().items()}
    assert len(set(counts.values())) == 1, f"categories not balanced: {counts}"

    for q in HARD_QUERY_SET:
        assert q["prompt"].strip() and q["reference"].strip(), f"empty field in {q['id']}"
        # The ONE property that defines this set: the reference must enumerate enough
        # checkable substance that a partly-right answer scores partly. A one-line
        # reference is what pinned 31/36 of the base set at the grader's ceiling, so a
        # short reference here is a BUG in the query, not a terse style choice.
        assert len(q["reference"]) >= 300, (
            f"{q['id']}: reference is too thin ({len(q['reference'])} chars) to give the "
            f"grader resolution — it will saturate at 5/5 like the base set did")

    print(f"ok — {len(HARD_QUERY_SET)} hard queries, balanced: {counts}, "
          f"no id collision with the base {len(QUERY_SET)}")


if __name__ == "__main__":
    demo()
